internal final class UBSOutboundInterfaceBatchService_Vendor extends SysOperationServiceBase
{
}

Method.Source:
    public void Process()
    {
        UBSOutboundInterfaceEndPoint outboundInterfaceEndPoint = UBSOutboundInterfaceEndPoint::findByEndPointType(UBSEndPointType::Vendor);
        UBSOutboundInterface         outboundInterface         = UBSOutboundInterface::findUBSOutboundInterface();
        System.Collections.ArrayList outbountList;
        System.Object[]              returnedCode;

        UBSInterfaceExecutionHistoryTable execution;
        boolean ret;

        execution = UBSInterfaceExecutionHistoryTable::insertExecution(UBSEndPointType::Vendor);
        
        try
        {
            str bearer = UBSOutboundInterfaceToolkit::getBearer();

            ret = UBSOutboundInterfaceIntegrator::postInterface(outboundInterfaceEndPoint,bearer,execution);

            if(ret)
            {
                execution.updateStatus(UBSInterfaceStatus::Processed);
            }
            else
            {
                execution.updateStatus(UBSInterfaceStatus::Failed);
            }
        }
        catch
        {
            System.Exception ex = CLRInterop::getLastException();

            if(ex)
            {
                execution.updateStatus(UBSInterfaceStatus::Failed,ex.InnerException.ToString());
            }
            else
            {
                execution.updateStatus(UBSInterfaceStatus::Failed,"Unknown error");
            }
        }
    }
